340→export default function ManageBooksScreen(): JSX.Element {
341→  const { t } = useTranslation();
342→  const theme = useTheme();
343→  const colors = getColors(theme);
344→  const insets = useSafeAreaInsets();
345→  const isDark = theme === "dark";
346→  const textColor = isDark ? "#FFFFFF" : "#000000";
347→  const { sources, createSource, renameSource, setSourceLanguage, deleteSource } = useSources();
348→  const { recipes, deleteRecipes } = useRecipes();
349→  const { addToQueue } = useBackgroundProcessing();
350→  const isDeletingRef = useRef(false);
351→
352→  const [isAddingBook, setIsAddingBook] = useState(false);
353→  const [newBookName, setNewBookName] = useState("");
354→  const [editingSourceId, setEditingSourceId] = useState<SourceId | null>(null);
355→  const [editText, setEditText] = useState("");
356→
357→  const recipeCounts = useMemo(() => {
358→    const counts = new Map<SourceId, number>();
359→    for (const recipe of recipes) {
360→      const src = recipe.metadata.source;
361→      if (src && !isUrl(src)) {
362→        counts.set(src, (counts.get(src) ?? 0) + 1);
363→      }
364→    }
365→    return counts;
366→  }, [recipes]);
367→
368→  const handleStartAdd = useCallback(() => {
369→    setIsAddingBook(true);
370→    setNewBookName("");
371→  }, []);
372→
373→  const handleCancelAdd = useCallback(() => {
374→    setIsAddingBook(false);
375→    setNewBookName("");
376→  }, []);
377→
378→  const handleConfirmAdd = useCallback(async () => {
379→    const trimmed = newBookName.trim();
380→    if (!trimmed) return;
381→    try {
382→      await createSource(trimmed);
383→      setIsAddingBook(false);
384→      setNewBookName("");
385→    } catch (error) {
386→      const message = error instanceof Error ? error.message : "";
387→      if (!message.includes("already exists") && !message.includes("cannot be empty") && !message.includes("too long")) {
388→        console.warn("Unexpected error adding book:", error);
389→      }
390→    }
391→  }, [newBookName, createSource]);
392→
393→  const handleDeleteBook = useCallback(
394→    (sourceId: SourceId) => {
395→      if (isDeletingRef.current) return;
396→      const source = sources.find((s) => s.id === sourceId);
397→      if (!source) return;
398→      const count = recipeCounts.get(sourceId) ?? 0;
399→
400→      Alert.alert(
401→        t("manageBooks.deleteConfirmTitle", { name: source.name }),
402→        t("manageBooks.deleteConfirmMessage", { count }),
403→        [
404→          { text: t("manageBooks.deleteConfirmCancel"), style: "cancel" },
405→          {
406→            text: t("manageBooks.deleteConfirmAction"),
407→            style: "destructive",
408→            onPress: async () => {
409→              isDeletingRef.current = true;
410→              try {
411→                if (Platform.OS !== "web") {
412→                  Haptics.notificationAsync(
413→                    Haptics.NotificationFeedbackType.Warning
414→                  );
415→                }
416→                const recipesToDelete = recipes.filter(
417→                  (r) => r.metadata.source === sourceId
418→                );
419→                await deleteRecipes(recipesToDelete.map((recipe) => recipe.id));
420→                LayoutAnimation.configureNext(
421→                  LayoutAnimation.Presets.easeInEaseOut
422→                );
423→                await deleteSource(sourceId);
424→              } finally {
425→                isDeletingRef.current = false;
426→              }
427→            },
428→          },
429→        ]
430→      );
431→    },
432→    [sources, recipeCounts, recipes, deleteRecipes, deleteSource, t]
433→  );
434→
435→  const handleStartEdit = useCallback(
436→    (sourceId: SourceId) => {
437→      const source = sources.find((s) => s.id === sourceId);
438→      if (!source) return;
439→      setEditingSourceId(sourceId);
440→      setEditText(source.name);
441→    },
442→    [sources]
443→  );
444→
445→  const handleConfirmEdit = useCallback(async () => {
446→    if (!editingSourceId) return;
447→    const trimmed = editText.trim();
448→    if (trimmed) {
449→      try {
450→        await renameSource(editingSourceId, trimmed);
451→      } catch (error) {
452→        const message = error instanceof Error ? error.message : "";
453→        if (!message.includes("already exists") && !message.includes("cannot be empty") && !message.includes("too long")) {
454→          console.warn("Unexpected error renaming book:", error);
455→        }
456→      }
457→    }
458→    setEditingSourceId(null);
459→    setEditText("");
460→  }, [editingSourceId, editText, renameSource]);
461→
462→  const handleCancelEdit = useCallback(() => {
463→    setEditingSourceId(null);
464→    setEditText("");
465→  }, []);
466→
467→  const handleSetLanguage = useCallback(
468→    (sourceId: SourceId, onDone: () => void) => {
469→      const source = sources.find((s) => s.id === sourceId);
470→      if (!source) return;
471→
472→      const options = APP_LANGUAGES.map((lang) => ({
473→        text: LANGUAGE_DISPLAY_NAMES[lang],
474→        onPress: async () => {
475→          onDone();
476→          if (lang === source.language) return;
477→          await setSourceLanguage(sourceId, lang);
478→          const sourceRecipes = recipes.filter(
479→            (r) => r.metadata.source === sourceId
480→          );
481→          for (const recipe of sourceRecipes) {
482→            addToQueue(recipe.id);
483→          }
484→        },
485→      }));
486→
487→      Alert.alert(
488→        t("manageBooks.setLanguageAction"),
489→        undefined,
490→        [
491→          ...options,
492→          { text: t("manageBooks.deleteConfirmCancel"), style: "cancel", onPress: onDone },
493→        ]
494→      );
495→    },
496→    [sources, recipes, setSourceLanguage, addToQueue, t]
497→  );
498→
499→  return (
500→    <View style={[styles.container, { backgroundColor: colors.background }]}>
501→      <View style={[styles.header, { paddingTop: insets.top + 16 }]}>
502→        <Text style={[styles.headerTitle, { color: textColor }]}>
503→          {t("manageBooks.title")}
504→        </Text>
505→      </View>
506→
507→      {sources.length === 0 && !isAddingBook ? (
508→        <View style={styles.emptyState}>
509→          <Text style={[styles.emptyStateText, { color: colors.textSecondary }]}>
510→            {t("manageBooks.emptyState")}
511→          </Text>
512→        </View>
513→      ) : (
514→        <ScrollView
515→          style={styles.list}
516→          contentContainerStyle={styles.listContent}
517→        >
518→          {sources.map((source) => (
519→            <SwipeableBookRow
520→              key={source.id}
521→              source={source}
522→              recipeCount={recipeCounts.get(source.id) ?? 0}
523→              editingSourceId={editingSourceId}
524→              onDelete={handleDeleteBook}
525→              onStartEdit={handleStartEdit}
526→              onSetLanguage={handleSetLanguage}
527→              onConfirmEdit={handleConfirmEdit}
528→              onCancelEdit={handleCancelEdit}
529→              editText={editText}
530→              onEditTextChange={setEditText}
531→            />
532→          ))}
533→        </ScrollView>
534→      )}
535→
536→      <KeyboardAvoidingView
537→        behavior={Platform.OS === "ios" ? "padding" : "height"}
538→        style={styles.keyboardAvoid}
539→      >
540→        <View style={styles.bottomBar}>
541→          {isAddingBook ? (
542→            <>
543→              <LiquidGlassButton
544→                onPress={handleCancelAdd}
545→                systemImage="xmark"
546→                accessibilityLabel={t("manageBooks.deleteConfirmCancel")}
547→              />
548→              <View style={styles.addInput}>
549→                <LiquidGlassInput
550→                  value={newBookName}
551→                  onChangeText={setNewBookName}
552→                  placeholder={t("sourceSelector.addNewPlaceholder")}
553→                  variant="text"
554→                  style={styles.addInputField}
555→                  autoFocus
556→                  maxLength={100}
557→                  returnKeyType="done"
558→                  onSubmitEditing={handleConfirmAdd}
559→                />
560→              </View>
561→              <LiquidGlassButton
562→                onPress={handleConfirmAdd}
563→                systemImage="checkmark"
564→                accessibilityLabel={t("accessibility.confirm")}
565→              />
566→            </>
567→          ) : (
568→            <>
569→              <LiquidGlassButton
570→                onPress={router.back}
571→                systemImage="chevron.left"
572→                accessibilityLabel={t("manageBooks.back")}
573→              />
574→              <View style={styles.spacer} />
575→              <LiquidGlassButton
576→                onPress={handleStartAdd}
577→                systemImage="plus"
578→                accessibilityLabel={t("manageBooks.addBook")}
579→              />
580→            </>
581→          )}
582→        </View>
583→      </KeyboardAvoidingView>
584→    </View>
585→  );
586→}
