 23→  photoUri: PhotoUri;
 24→  source: SourceId;
 25→  onSourceChange: (sourceId: SourceId, isAutomatic?: boolean) => void;
 26→  onConfirm: (sourceOverride?: SourceId) => void;
 27→}): JSX.Element {
