            .foregroundStyle(.primary)

          inputContainer
        }
      } else {
        inputContainer
      }
    }
    .onAppear {
      lglog.error("[LGInput] .onAppear autoFocus=\(autoFocus) focusedOverride=\(String(describing: focusedOverride)) hasAppliedInitialFocus=\(hasAppliedInitialFocus) variant=\(variant)")
      text = value
      if autoFocus && focusedOverride == nil && !hasAppliedInitialFocus {
        hasAppliedInitialFocus = true
        isTextInputFocused = true
        lglog.error("[LGInput] .onAppear → setting isTextInputFocused=true")
      }
    }
    .onChange(of: value) { _, newValue in
      if text != newValue {
        lglog.error("[LGInput] .onChange(value) '\(text.prefix(10))' → '\(newValue.prefix(10))'")
        text = newValue
      }
    }
  }

  @ViewBuilder
  private var inputRow: some View {
    HStack(spacing: 4) {
      if let imageName = leadingSystemImage {
        Image(systemName: imageName)
          .font(.system(size: 20))
          .foregroundStyle(.primary)
      }

      inlineContent

      if showClearButton && hasClearableContent {
        Button(action: {
          text = ""
          onClear()
          onChangeText("")
        }) {
          Image(systemName: "xmark.circle.fill")
            .font(.system(size: 20))
            .foregroundStyle(.secondary)
        }
        .buttonStyle(.plain)
      }
    }
    .onChange(of: text) { _, newValue in
      onChangeText(newValue)
    }
  }

  private var inputContainer: some View {
    inputRow
      .frame(maxWidth: .infinity, maxHeight: .infinity)
      .padding(.horizontal, 16)
      .background {
        RoundedRectangle(cornerRadius: 24)
          .fill(.ultraThinMaterial)
      }
  }

  @ViewBuilder
  private var inlineContent: some View {
    if shouldShowTags || shouldShowTextField {
      GeometryReader { geometry in
        ScrollViewReader { scrollProxy in
          ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 6) {
              if shouldShowTags {
                ForEach(selectedTags) { tag in
                  Button(action: {
                    onTagPress(tag.id)
                  }) {
                    Text(tag.label)
                      .font(.system(size: 14, weight: .medium))
                      .foregroundStyle(
                        shouldUseAccent
                          ? accentPillTextColor
                          : .primary
                      )
                      .padding(.horizontal, 4)
                      .padding(.vertical, 4)
                      .background(
                        RoundedRectangle(cornerRadius: 8, style: .continuous)
                          .fill(
                            shouldUseAccent
                              ? accentPillBackgroundColor
                              : Color(white: 0.82, opacity: 0.75)
                          )
                      )
                  }
                  .buttonStyle(.plain)
                  .accessibilityLabel(tag.accessibilityLabel ?? tag.label)
                }
              }

              if shouldShowTextField {
                BackspaceAwareTextField(
                  text: $text,
                  placeholder: placeholder,
                  returnKeyType: uiReturnKeyType,
                  isFocused: Binding(
                    get: {
                      effectiveIsFocused
                    },
                    set: { newValue in
                      if focusedOverride == nil {
                        isTextInputFocused = newValue
                      }
                    }
                  ),
                  blurOnSubmit: blurOnSubmit,
                  onFocus: onFocus,
                  onBlur: onBlur,
                  onSubmit: onSubmitEditing,
                  onEmptyBackspace: {
                    guard variant == "mixed", text.isEmpty, let lastTag = selectedTags.last else {
                      return
                    }

                    onTagPress(lastTag.id)
                  }
                )
                .frame(minWidth: 80, idealWidth: selectedTags.isEmpty ? geometry.size.width : 120)
                .frame(height: 30)
                .id("input-tail")
              } else {
                Color.clear
                  .frame(width: 1, height: 1)
                  .id("input-tail")
              }
            }
            .padding(.vertical, 2)
          }
          .onAppear {
            if hasScrollableContent {
              scrollInlineContentToTail(scrollProxy: scrollProxy, animated: false)
            }
          }
          .onChange(of: selectedTagIdSignature) { _, _ in
            scrollInlineContentToTail(scrollProxy: scrollProxy, animated: true)
          }
          .onChange(of: text) { _, _ in
            scrollInlineContentToTail(scrollProxy: scrollProxy, animated: true)
          }
          .onChange(of: isTextInputFocused) { _, focused in
            if focused && hasScrollableContent {
              scrollInlineContentToTail(scrollProxy: scrollProxy, animated: true)
            }
          }
          .onChange(of: focusedOverride) { _, focused in
            if focused == true && hasScrollableContent {
              scrollInlineContentToTail(scrollProxy: scrollProxy, animated: true)
            }
          }
          .frame(maxHeight: .infinity)
        }
      }
      .frame(maxWidth: .infinity, alignment: .leading)
    }
  }

  private var selectedTagIdSignature: String {
    selectedTags.map(\.id).joined(separator: "|")
  }

  private var accentPillBackgroundColor: Color {
    colorScheme == .dark
      ? darkModeAccentPillBackgroundColor
      : lightModeAccentPillBackgroundColor
  }

  private var accentPillTextColor: Color {
    colorScheme == .dark
      ? darkModeAccentPillTextColor
      : lightModeAccentPillTextColor
  }

  private func scrollInlineContentToTail(
    scrollProxy: ScrollViewProxy,
    animated: Bool
  ) {
    let action = {
      scrollProxy.scrollTo("input-tail", anchor: .trailing)
    }

    DispatchQueue.main.async {
      if animated {
        withAnimation(.easeOut(duration: 0.16)) {
          action()
        }
      } else {
        action()
      }
    }
  }
}

private final class DeletingAwareUITextField: UITextField {
  var onEmptyBackspace: (() -> Void)?

  override var intrinsicContentSize: CGSize {
    CGSize(width: UIView.noIntrinsicMetric, height: super.intrinsicContentSize.height)
  }

  override func deleteBackward() {
    if (text ?? "").isEmpty {
      onEmptyBackspace?()
    }

    super.deleteBackward()
  }
}

private struct BackspaceAwareTextField: UIViewRepresentable {
  @Binding var text: String
  var placeholder: String
  var returnKeyType: UIReturnKeyType
  @Binding var isFocused: Bool
  var blurOnSubmit: Bool
  var onFocus: () -> Void
  var onBlur: () -> Void
  var onSubmit: () -> Void
  var onEmptyBackspace: () -> Void

  func makeUIView(context: Context) -> DeletingAwareUITextField {
    lglog.error("[LGInput] makeUIView (new UITextField created)")
    let textField = DeletingAwareUITextField(frame: .zero)
    textField.borderStyle = .none
    textField.font = UIFont.systemFont(ofSize: 16)
    textField.textColor = .label
    textField.backgroundColor = .clear
    textField.returnKeyType = returnKeyType
    textField.placeholder = placeholder
    textField.attributedPlaceholder = NSAttributedString(
      string: placeholder,
      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
    )
    textField.delegate = context.coordinator
    textField.onEmptyBackspace = onEmptyBackspace
    textField.addTarget(
      context.coordinator,
      action: #selector(Coordinator.handleEditingChanged(_:)),
      for: .editingChanged
    )
    return textField
  }

  func updateUIView(_ uiView: DeletingAwareUITextField, context: Context) {
    if uiView.text != text {
      uiView.text = text
    }

    uiView.returnKeyType = returnKeyType
    uiView.placeholder = placeholder
    uiView.attributedPlaceholder = NSAttributedString(
      string: placeholder,
      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
    )
    uiView.onEmptyBackspace = onEmptyBackspace

    // Keep coordinator's closures in sync with the latest values
    context.coordinator.update(
      text: $text,
      isFocused: $isFocused,
      blurOnSubmit: blurOnSubmit,
      onFocus: onFocus,
      onBlur: onBlur,
      onSubmit: onSubmit
    )

    let isFirst = uiView.isFirstResponder
    if isFocused && !isFirst {
      lglog.error("[LGInput] updateUIView → becomeFirstResponder (isFocused=true, isFirstResponder=false)")
      uiView.becomeFirstResponder()
    } else if !isFocused && isFirst {
      lglog.error("[LGInput] updateUIView → resignFirstResponder (isFocused=false, isFirstResponder=true)")
      uiView.resignFirstResponder()
    }
  }

  func makeCoordinator() -> Coordinator {
    Coordinator(
      text: $text,
      isFocused: $isFocused,
      blurOnSubmit: blurOnSubmit,
      onFocus: onFocus,
      onBlur: onBlur,
      onSubmit: onSubmit
    )
  }

  final class Coordinator: NSObject, UITextFieldDelegate {
    private var text: Binding<String>
    private var isFocused: Binding<Bool>
    private var blurOnSubmit: Bool
    private var onFocus: () -> Void
    private var onBlur: () -> Void
    private var onSubmit: () -> Void

    init(
      text: Binding<String>,
      isFocused: Binding<Bool>,
      blurOnSubmit: Bool,
      onFocus: @escaping () -> Void,
      onBlur: @escaping () -> Void,
      onSubmit: @escaping () -> Void
    ) {
      self.text = text
      self.isFocused = isFocused
      self.blurOnSubmit = blurOnSubmit
      self.onFocus = onFocus
      self.onBlur = onBlur
      self.onSubmit = onSubmit
    }

    func update(
      text: Binding<String>,
      isFocused: Binding<Bool>,
      blurOnSubmit: Bool,
      onFocus: @escaping () -> Void,
      onBlur: @escaping () -> Void,
      onSubmit: @escaping () -> Void
    ) {
      self.text = text
      self.isFocused = isFocused
      self.blurOnSubmit = blurOnSubmit
      self.onFocus = onFocus
      self.onBlur = onBlur
      self.onSubmit = onSubmit
    }

    @objc
    func handleEditingChanged(_ textField: UITextField) {
      text.wrappedValue = textField.text ?? ""
    }

    func textFieldDidBeginEditing(_ textField: UITextField) {
      lglog.error("[LGInput] textFieldDidBeginEditing isFocused.wrappedValue=\(isFocused.wrappedValue)")
      if !isFocused.wrappedValue {
        isFocused.wrappedValue = true
      }
      onFocus()
    }

    func textFieldDidEndEditing(_ textField: UITextField) {
      lglog.error("[LGInput] textFieldDidEndEditing isFocused.wrappedValue=\(isFocused.wrappedValue)")
      if isFocused.wrappedValue {
        isFocused.wrappedValue = false
      }
      onBlur()
    }

    func textFieldShouldReturn(_ textField: UITextField) -> Bool {
      lglog.error("[LGInput] textFieldShouldReturn blurOnSubmit=\(blurOnSubmit)")
      onSubmit()
      if blurOnSubmit {
        lglog.error("[LGInput] textFieldShouldReturn → resignFirstResponder")
        isFocused.wrappedValue = false
        textField.resignFirstResponder()
      }
      return true
    }
  }
}

