      onChangeText: { [weak self] text in
        self?.onChangeText(["text": text])
      },
      onClear: { [weak self] in
        self?.onClear()
      },
      onTagPress: { [weak self] id in
        self?.onTagPress(["id": id])
      },
      onFocus: { [weak self] in
        self?.onInputFocus()
      },
      onBlur: { [weak self] in
        self?.onInputBlur()
      },
      onSubmitEditing: { [weak self] in
        self?.onInputSubmit()
      }
    )
    hostingController.rootView = content
  }

  public override func didMoveToWindow() {
    super.didMoveToWindow()
    lglog.error("[LGInput] didMoveToWindow window=\(window != nil ? "YES" : "nil", privacy: .public) variant=\(variant, privacy: .public)")
    if window != nil {
      if let parentVC = findViewController() {
        parentVC.addChild(hostingController)
        hostingController.didMove(toParent: parentVC)
      }
    } else {
      hostingController.view.endEditing(true)
      hostingController.willMove(toParent: nil)
      hostingController.removeFromParent()
    }
  }

  private func findViewController() -> UIViewController? {
    var responder: UIResponder? = self
    while let nextResponder = responder?.next {
      if let viewController = nextResponder as? UIViewController {
        return viewController
      }
      responder = nextResponder
    }
    return nil
  }
