233→  private func findViewController() -> UIViewController? {
234→    var responder: UIResponder? = self
235→    while let nextResponder = responder?.next {
236→      if let viewController = nextResponder as? UIViewController {
237→        return viewController
238→      }
239→      responder = nextResponder
240→    }
241→    return nil
242→  }
