245→private struct LiquidGlassInputContent: View {
246→  var value: String
247→  var label: String?
248→  var placeholder: String
249→  var leadingSystemImage: String?
250→  var showClearButton: Bool
251→  var variant: String
252→  var selectedTags: [LiquidGlassSelectedTag]
253→  var autoFocus: Bool
254→  var focusedOverride: Bool?
255→  var returnKeyType: String
256→  var blurOnSubmit: Bool
257→  var onChangeText: (String) -> Void
258→  var onClear: () -> Void
259→  var onTagPress: (String) -> Void
260→  var onFocus: () -> Void
261→  var onBlur: () -> Void
262→  var onSubmitEditing: () -> Void
263→  
264→  @State private var text: String = ""
265→  @State private var isTextInputFocused: Bool = false
266→  @State private var hasAppliedInitialFocus: Bool = false
267→  @Environment(\.colorScheme) private var colorScheme
268→
269→  private var shouldShowTags: Bool {
270→    variant == "tags" || variant == "mixed"
271→  }
272→
273→  private var shouldShowTextField: Bool {
274→    variant == "text" || variant == "mixed"
275→  }
276→
277→  private var shouldUseAccent: Bool {
278→    shouldShowTags && !selectedTags.isEmpty && !value.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
279→  }
280→
281→  private var hasScrollableContent: Bool {
282→    !selectedTags.isEmpty || !text.isEmpty
283→  }
284→
285→  private var shouldUseCapsuleShape: Bool {
286→    variant == "tags" || variant == "mixed"
287→  }
288→
289→  private var hasClearableContent: Bool {
290→    !value.isEmpty || !selectedTags.isEmpty
291→  }
292→
293→  private var uiReturnKeyType: UIReturnKeyType {
294→    switch returnKeyType {
295→    case "next":
296→      return .next
297→    case "search":
298→      return .search
299→    default:
300→      return .done
301→    }
302→  }
303→
304→  private var effectiveIsFocused: Bool {
305→    focusedOverride ?? isTextInputFocused
306→  }
307→  
308→  var body: some View {
309→    Group {
310→      if let labelText = label, !labelText.isEmpty, variant == "text" {
311→        VStack(alignment: .leading, spacing: 8) {
312→          Text(labelText)
313→            .font(.system(size: 16, weight: .medium))
314→            .foregroundStyle(.primary)
315→
316→          inputContainer
