318→      } else {
319→        inputContainer
320→      }
321→    }
322→    .onAppear {
323→      lglog.error("[LGInput] .onAppear autoFocus=\(autoFocus, privacy: .public) focusedOverride=\(String(describing: focusedOverride), privacy: .public) hasAppliedInitialFocus=\(hasAppliedInitialFocus, privacy: .public) variant=\(variant, privacy: .public)")
324→      text = value
325→      if autoFocus && focusedOverride == nil && !hasAppliedInitialFocus {
326→        hasAppliedInitialFocus = true
327→        isTextInputFocused = true
328→        lglog.error("[LGInput] .onAppear → setting isTextInputFocused=true")
329→      }
330→    }
331→    .onChange(of: value) { _, newValue in
332→      if text != newValue {
333→        lglog.error("[LGInput] .onChange(value) '\(text.prefix(10), privacy: .public)' → '\(newValue.prefix(10), privacy: .public)'")
334→        text = newValue
335→      }
336→    }
