338→
339→  @ViewBuilder
340→  private var inputRow: some View {
341→    HStack(spacing: 4) {
342→      if let imageName = leadingSystemImage {
343→        Image(systemName: imageName)
344→          .font(.system(size: 20))
345→          .foregroundStyle(.primary)
346→      }
347→
348→      inlineContent
349→
350→      if showClearButton && hasClearableContent {
351→        Button(action: {
352→          text = ""
353→          onClear()
354→          onChangeText("")
355→        }) {
356→          Image(systemName: "xmark.circle.fill")
