375→      }
376→  }
377→
378→  @ViewBuilder
379→  private var inlineContent: some View {
380→    if shouldShowTags || shouldShowTextField {
381→      GeometryReader { geometry in
382→        ScrollViewReader { scrollProxy in
383→          ScrollView(.horizontal, showsIndicators: false) {
384→            HStack(spacing: 6) {
385→              if shouldShowTags {
386→                ForEach(selectedTags) { tag in
387→                  Button(action: {
388→                    onTagPress(tag.id)
389→                  }) {
390→                    Text(tag.label)
391→                      .font(.system(size: 14, weight: .medium))
392→                      .foregroundStyle(
393→                        shouldUseAccent
394→                          ? accentPillTextColor
395→                          : .primary
396→                      )
397→                      .padding(.horizontal, 4)
398→                      .padding(.vertical, 4)
399→                      .background(
400→                        RoundedRectangle(cornerRadius: 8, style: .continuous)
401→                          .fill(
402→                            shouldUseAccent
403→                              ? accentPillBackgroundColor
404→                              : Color(white: 0.82, opacity: 0.75)
405→                          )
406→                      )
407→                  }
408→                  .buttonStyle(.plain)
409→                  .accessibilityLabel(tag.accessibilityLabel ?? tag.label)
410→                }
411→              }
412→
413→              if shouldShowTextField {
414→                BackspaceAwareTextField(
415→                  text: $text,
416→                  placeholder: placeholder,
417→                  returnKeyType: uiReturnKeyType,
418→                  isFocused: Binding(
419→                    get: {
420→                      effectiveIsFocused
421→                    },
422→                    set: { newValue in
423→                      if focusedOverride == nil {
424→                        isTextInputFocused = newValue
425→                      }
426→                    }
427→                  ),
428→                  blurOnSubmit: blurOnSubmit,
429→                  onFocus: onFocus,
430→                  onBlur: onBlur,
431→                  onSubmit: onSubmitEditing,
432→                  onEmptyBackspace: {
433→                    guard variant == "mixed", text.isEmpty, let lastTag = selectedTags.last else {
434→                      return
435→                    }
436→
437→                    onTagPress(lastTag.id)
438→                  }
439→                )
440→                .frame(minWidth: 80, idealWidth: selectedTags.isEmpty ? geometry.size.width : 120)
441→                .frame(height: 30)
442→                .id("input-tail")
443→              } else {
444→                Color.clear
445→                  .frame(width: 1, height: 1)
446→                  .id("input-tail")
447→              }
448→            }
449→            .padding(.vertical, 2)
450→          }
451→          .onAppear {
452→            if hasScrollableContent {
453→              scrollInlineContentToTail(scrollProxy: scrollProxy, animated: false)
454→            }
455→          }
456→          .onChange(of: selectedTagIdSignature) { _, _ in
457→            scrollInlineContentToTail(scrollProxy: scrollProxy, animated: true)
458→          }
459→          .onChange(of: text) { _, _ in
460→            scrollInlineContentToTail(scrollProxy: scrollProxy, animated: true)
461→          }
462→          .onChange(of: isTextInputFocused) { _, focused in
463→            if focused && hasScrollableContent {
464→              scrollInlineContentToTail(scrollProxy: scrollProxy, animated: true)
465→            }
466→          }
467→          .onChange(of: focusedOverride) { _, focused in
468→            if focused == true && hasScrollableContent {
469→              scrollInlineContentToTail(scrollProxy: scrollProxy, animated: true)
470→            }
471→          }
472→          .frame(maxHeight: .infinity)
473→        }
474→      }
475→      .frame(maxWidth: .infinity, alignment: .leading)
476→    }
477→  }
478→
479→  private var selectedTagIdSignature: String {
480→    selectedTags.map(\.id).joined(separator: "|")
481→  }
482→
483→  private var accentPillBackgroundColor: Color {
484→    colorScheme == .dark
485→      ? darkModeAccentPillBackgroundColor
486→      : lightModeAccentPillBackgroundColor
487→  }
488→
489→  private var accentPillTextColor: Color {
490→    colorScheme == .dark
491→      ? darkModeAccentPillTextColor
492→      : lightModeAccentPillTextColor
493→  }
494→
495→  private func scrollInlineContentToTail(
496→    scrollProxy: ScrollViewProxy,
497→    animated: Bool
498→  ) {
499→    let action = {
500→      scrollProxy.scrollTo("input-tail", anchor: .trailing)
501→    }
502→
503→    DispatchQueue.main.async {
504→      if animated {
505→        withAnimation(.easeOut(duration: 0.16)) {
506→          action()
507→        }
508→      } else {
509→        action()
510→      }
511→    }
512→  }
513→}
