515→private final class DeletingAwareUITextField: UITextField {
516→  var onEmptyBackspace: (() -> Void)?
517→
518→  override var intrinsicContentSize: CGSize {
519→    CGSize(width: UIView.noIntrinsicMetric, height: super.intrinsicContentSize.height)
520→  }
521→
522→  override func deleteBackward() {
523→    if (text ?? "").isEmpty {
524→      onEmptyBackspace?()
525→    }
526→
527→    super.deleteBackward()
528→  }
529→}
