531→private struct BackspaceAwareTextField: UIViewRepresentable {
532→  @Binding var text: String
533→  var placeholder: String
534→  var returnKeyType: UIReturnKeyType
535→  @Binding var isFocused: Bool
536→  var blurOnSubmit: Bool
537→  var onFocus: () -> Void
538→  var onBlur: () -> Void
539→  var onSubmit: () -> Void
540→  var onEmptyBackspace: () -> Void
541→
542→  func makeUIView(context: Context) -> DeletingAwareUITextField {
543→    lglog.error("[LGInput] makeUIView (new UITextField created)")
544→    let textField = DeletingAwareUITextField(frame: .zero)
545→    textField.borderStyle = .none
546→    textField.font = UIFont.systemFont(ofSize: 16)
547→    textField.textColor = .label
548→    textField.backgroundColor = .clear
549→    textField.returnKeyType = returnKeyType
550→    textField.placeholder = placeholder
551→    textField.attributedPlaceholder = NSAttributedString(
552→      string: placeholder,
553→      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
554→    )
555→    textField.delegate = context.coordinator
556→    textField.onEmptyBackspace = onEmptyBackspace
557→    textField.addTarget(
558→      context.coordinator,
559→      action: #selector(Coordinator.handleEditingChanged(_:)),
560→      for: .editingChanged
561→    )
562→    return textField
563→  }
564→
565→  func updateUIView(_ uiView: DeletingAwareUITextField, context: Context) {
566→    if uiView.text != text {
567→      uiView.text = text
568→    }
569→
570→    uiView.returnKeyType = returnKeyType
571→    uiView.placeholder = placeholder
572→    uiView.attributedPlaceholder = NSAttributedString(
573→      string: placeholder,
574→      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
575→    )
576→    uiView.onEmptyBackspace = onEmptyBackspace
577→
578→    // Keep coordinator's closures in sync with the latest values
579→    context.coordinator.update(
580→      text: $text,
581→      isFocused: $isFocused,
582→      blurOnSubmit: blurOnSubmit,
583→      onFocus: onFocus,
584→      onBlur: onBlur,
585→      onSubmit: onSubmit
586→    )
587→
588→    let isFirst = uiView.isFirstResponder
589→    if isFocused && !isFirst {
590→      lglog.error("[LGInput] updateUIView → becomeFirstResponder (isFocused=true, isFirstResponder=false)")
591→      uiView.becomeFirstResponder()
592→    } else if !isFocused && isFirst {
593→      lglog.error("[LGInput] updateUIView → resignFirstResponder (isFocused=false, isFirstResponder=true)")
594→      uiView.resignFirstResponder()
595→    }
596→  }
597→
598→  func makeCoordinator() -> Coordinator {
599→    Coordinator(
600→      text: $text,
601→      isFocused: $isFocused,
602→      blurOnSubmit: blurOnSubmit,
603→      onFocus: onFocus,
604→      onBlur: onBlur,
605→      onSubmit: onSubmit
606→    )
607→  }
608→
609→  final class Coordinator: NSObject, UITextFieldDelegate {
610→    private var text: Binding<String>
611→    private var isFocused: Binding<Bool>
612→    private var blurOnSubmit: Bool
613→    private var onFocus: () -> Void
614→    private var onBlur: () -> Void
615→    private var onSubmit: () -> Void
616→
617→    init(
618→      text: Binding<String>,
619→      isFocused: Binding<Bool>,
620→      blurOnSubmit: Bool,
621→      onFocus: @escaping () -> Void,
622→      onBlur: @escaping () -> Void,
623→      onSubmit: @escaping () -> Void
624→    ) {
625→      self.text = text
626→      self.isFocused = isFocused
627→      self.blurOnSubmit = blurOnSubmit
628→      self.onFocus = onFocus
629→      self.onBlur = onBlur
630→      self.onSubmit = onSubmit
631→    }
632→
633→    func update(
634→      text: Binding<String>,
635→      isFocused: Binding<Bool>,
636→      blurOnSubmit: Bool,
637→      onFocus: @escaping () -> Void,
638→      onBlur: @escaping () -> Void,
639→      onSubmit: @escaping () -> Void
640→    ) {
641→      self.text = text
642→      self.isFocused = isFocused
643→      self.blurOnSubmit = blurOnSubmit
644→      self.onFocus = onFocus
645→      self.onBlur = onBlur
646→      self.onSubmit = onSubmit
647→    }
648→
649→    @objc
650→    func handleEditingChanged(_ textField: UITextField) {
651→      text.wrappedValue = textField.text ?? ""
652→    }
653→
654→    func textFieldDidBeginEditing(_ textField: UITextField) {
655→      let focused = self.isFocused.wrappedValue
656→      lglog.error("[LGInput] textFieldDidBeginEditing isFocused.wrappedValue=\(focused, privacy: .public)")
657→      if !isFocused.wrappedValue {
658→        isFocused.wrappedValue = true
659→      }
660→      onFocus()
661→    }
662→
663→    func textFieldDidEndEditing(_ textField: UITextField) {
664→      let focused = self.isFocused.wrappedValue
665→      lglog.error("[LGInput] textFieldDidEndEditing isFocused.wrappedValue=\(focused, privacy: .public)")
666→      if isFocused.wrappedValue {
667→        isFocused.wrappedValue = false
668→      }
669→      onBlur()
670→    }
671→
672→    func textFieldShouldReturn(_ textField: UITextField) -> Bool {
673→      let blur = self.blurOnSubmit
674→      lglog.error("[LGInput] textFieldShouldReturn blurOnSubmit=\(blur, privacy: .public)")
675→      onSubmit()
676→      if blurOnSubmit {
677→        lglog.error("[LGInput] textFieldShouldReturn → resignFirstResponder")
678→        isFocused.wrappedValue = false
679→        textField.resignFirstResponder()
680→      }
681→      return true
682→    }
683→  }
684→}
