  func updateUIView(_ uiView: DeletingAwareUITextField, context: Context) {
    if uiView.text != text {
      uiView.text = text
    }

    uiView.returnKeyType = returnKeyType
    uiView.placeholder = placeholder
    uiView.attributedPlaceholder = NSAttributedString(
      string: placeholder,
      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
    )
    uiView.onEmptyBackspace = onEmptyBackspace

    // Keep coordinator's closures in sync with the latest values
    context.coordinator.update(
      text: $text,
      isFocused: $isFocused,
      blurOnSubmit: blurOnSubmit,
      onFocus: onFocus,
      onBlur: onBlur,
      onSubmit: onSubmit
    )

    let isFirst = uiView.isFirstResponder
    if isFocused && !isFirst && !context.coordinator.didEndEditing {
      lglog.error("[LGInput] updateUIView → becomeFirstResponder (isFocused=true, isFirstResponder=false)")
      uiView.becomeFirstResponder()
    } else if isFocused && !isFirst && context.coordinator.didEndEditing {
      lglog.error("[LGInput] updateUIView → SKIPPED becomeFirstResponder (didEndEditing=true)")
    } else if !isFocused && isFirst {
      lglog.error("[LGInput] updateUIView → resignFirstResponder (isFocused=false, isFirstResponder=true)")
      uiView.resignFirstResponder()
    }
  }

  func makeCoordinator() -> Coordinator {
    Coordinator(
      text: $text,
      isFocused: $isFocused,
      blurOnSubmit: blurOnSubmit,
      onFocus: onFocus,
      onBlur: onBlur,
      onSubmit: onSubmit
    )
  }

  final class Coordinator: NSObject, UITextFieldDelegate {
    private var text: Binding<String>
    private var isFocused: Binding<Bool>
    private var blurOnSubmit: Bool
    private var onFocus: () -> Void
    private var onBlur: () -> Void
    private var onSubmit: () -> Void
    /// Set when editing ends to prevent updateUIView from re-focusing
    /// before SwiftUI processes the isFocused binding change.
    var didEndEditing: Bool = false

    init(
      text: Binding<String>,
      isFocused: Binding<Bool>,
      blurOnSubmit: Bool,
      onFocus: @escaping () -> Void,
      onBlur: @escaping () -> Void,
      onSubmit: @escaping () -> Void
    ) {
      self.text = text
      self.isFocused = isFocused
      self.blurOnSubmit = blurOnSubmit
      self.onFocus = onFocus
      self.onBlur = onBlur
      self.onSubmit = onSubmit
    }

    func update(
      text: Binding<String>,
      isFocused: Binding<Bool>,
      blurOnSubmit: Bool,
      onFocus: @escaping () -> Void,
      onBlur: @escaping () -> Void,
      onSubmit: @escaping () -> Void
    ) {
      self.text = text
      self.isFocused = isFocused
      self.blurOnSubmit = blurOnSubmit
      self.onFocus = onFocus
      self.onBlur = onBlur
      self.onSubmit = onSubmit
    }

    @objc
    func handleEditingChanged(_ textField: UITextField) {
      text.wrappedValue = textField.text ?? ""
    }

    func textFieldDidBeginEditing(_ textField: UITextField) {
      let focused = self.isFocused.wrappedValue
      let ended = self.didEndEditing
      lglog.error("[LGInput] textFieldDidBeginEditing isFocused.wrappedValue=\(focused, privacy: .public) didEndEditing=\(ended, privacy: .public)")
      didEndEditing = false
      if !isFocused.wrappedValue {
        isFocused.wrappedValue = true
      }
      onFocus()
    }

    func textFieldDidEndEditing(_ textField: UITextField) {
      let focused = self.isFocused.wrappedValue
      lglog.error("[LGInput] textFieldDidEndEditing isFocused.wrappedValue=\(focused, privacy: .public)")
      didEndEditing = true
      if isFocused.wrappedValue {
        isFocused.wrappedValue = false
      }
      onBlur()
    }

    func textFieldShouldReturn(_ textField: UITextField) -> Bool {
      let blur = self.blurOnSubmit
      lglog.error("[LGInput] textFieldShouldReturn blurOnSubmit=\(blur, privacy: .public)")
      onSubmit()
      if blurOnSubmit {
        lglog.error("[LGInput] textFieldShouldReturn → resignFirstResponder")
        isFocused.wrappedValue = false
        textField.resignFirstResponder()
      }
      return true
    }
  }
}

