524→private struct BackspaceAwareTextField: UIViewRepresentable {
525→  @Binding var text: String
526→  var placeholder: String
527→  var returnKeyType: UIReturnKeyType
528→  @Binding var isFocused: Bool
529→  var blurOnSubmit: Bool
530→  var onFocus: () -> Void
531→  var onBlur: () -> Void
532→  var onSubmit: () -> Void
533→  var onEmptyBackspace: () -> Void
534→
535→  func makeUIView(context: Context) -> DeletingAwareUITextField {
536→    lglog.error("[LGInput] makeUIView (new UITextField created)")
537→    let textField = DeletingAwareUITextField(frame: .zero)
538→    textField.borderStyle = .none
539→    textField.font = UIFont.systemFont(ofSize: 16)
540→    textField.textColor = .label
541→    textField.backgroundColor = .clear
542→    textField.returnKeyType = returnKeyType
543→    textField.placeholder = placeholder
544→    textField.attributedPlaceholder = NSAttributedString(
545→      string: placeholder,
546→      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
547→    )
548→    textField.delegate = context.coordinator
549→    textField.onEmptyBackspace = onEmptyBackspace
550→    textField.addTarget(
551→      context.coordinator,
552→      action: #selector(Coordinator.handleEditingChanged(_:)),
553→      for: .editingChanged
554→    )
555→    return textField
556→  }
557→
558→  func updateUIView(_ uiView: DeletingAwareUITextField, context: Context) {
559→    if uiView.text != text {
560→      uiView.text = text
561→    }
562→
563→    uiView.returnKeyType = returnKeyType
564→    uiView.placeholder = placeholder
565→    uiView.attributedPlaceholder = NSAttributedString(
566→      string: placeholder,
567→      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
568→    )
569→    uiView.onEmptyBackspace = onEmptyBackspace
570→
571→    // Keep coordinator's closures in sync with the latest values
572→    context.coordinator.update(
573→      text: $text,
574→      isFocused: $isFocused,
575→      blurOnSubmit: blurOnSubmit,
576→      onFocus: onFocus,
577→      onBlur: onBlur,
578→      onSubmit: onSubmit
579→    )
580→
581→    let isFirst = uiView.isFirstResponder
582→    if isFocused && !isFirst && !context.coordinator.didEndEditing {
583→      lglog.error("[LGInput] updateUIView → becomeFirstResponder (isFocused=true, isFirstResponder=false)")
