181→  var fontSize: CGFloat
182→  var containerSize: CGFloat
183→  var tintColor: UIColor?
184→  var fillColor: UIColor?
185→  var fillProgress: CGFloat
186→  var onPress: () -> Void
187→
188→  private var resolvedFillColor: Color {
189→    if let fillColor = fillColor {
190→      return Color(fillColor)
191→    }
192→    if let tintColor = tintColor {
193→      return Color(tintColor)
194→    }
195→    return Color.blue
196→  }
197→
198→  private func fillOverlay(diameter: CGFloat) -> some View {
199→    GeometryReader { geo in
200→      Rectangle()
201→        .fill(resolvedFillColor.opacity(0.3))
202→        .frame(width: geo.size.width * fillProgress)
203→        .frame(maxHeight: .infinity, alignment: .leading)
204→    }
205→    .frame(width: diameter, height: diameter)
206→    .clipShape(Circle())
207→    .allowsHitTesting(false)
208→  }
209→
210→  var body: some View {
211→    GeometryReader { geometry in
212→      if #available(iOS 26.0, *) {
213→        Button(action: onPress) {
214→          ZStack {
215→            if fillProgress > 0 {
216→              fillOverlay(diameter: imageSize)
217→            }
218→            Image(systemName: systemImage)
219→              .font(.system(size: fontSize * imageScale))
220→              .foregroundStyle(tintColor.map { Color($0) } ?? .primary)
221→              .frame(width: imageSize, height: imageSize)
222→          }
223→        }
224→        .buttonBorderShape(.circle)
225→        .buttonStyle(.glass)
226→        .position(x: geometry.size.width / 2, y: geometry.size.height / 2)
227→      } else {
228→        Button(action: onPress) {
229→          ZStack {
230→            if fillProgress > 0 {
231→              fillOverlay(diameter: imageSize)
232→            }
233→            Image(systemName: systemImage)
234→              .font(.system(size: fontSize * imageScale))
235→              .foregroundStyle(tintColor.map { Color($0) } ?? .primary)
236→              .frame(width: imageSize, height: imageSize)
237→          }
238→        }
239→        .background {
240→          Circle()
241→            .fill(.ultraThinMaterial)
242→        }
243→        .buttonStyle(.plain)
244→        .position(x: geometry.size.width / 2, y: geometry.size.height / 2)
