213→  private func findViewController() -> UIViewController? {
214→    var responder: UIResponder? = self
215→    while let nextResponder = responder?.next {
216→      if let viewController = nextResponder as? UIViewController {
217→        return viewController
218→      }
219→      responder = nextResponder
220→    }
221→    return nil
222→  }
