475→  ) {
476→    let action = {
477→      scrollProxy.scrollTo("input-tail", anchor: .trailing)
478→    }
479→
480→    DispatchQueue.main.async {
481→      if animated {
482→        withAnimation(.easeOut(duration: 0.16)) {
483→          action()
484→        }
485→      } else {
486→        action()
487→      }
488→    }
489→  }
