508→private struct BackspaceAwareTextField: UIViewRepresentable {
509→  @Binding var text: String
510→  var placeholder: String
511→  var returnKeyType: UIReturnKeyType
512→  @Binding var isFocused: Bool
513→  var blurOnSubmit: Bool
514→  var onFocus: () -> Void
515→  var onBlur: () -> Void
516→  var onSubmit: () -> Void
517→  var onEmptyBackspace: () -> Void
518→
519→  func makeUIView(context: Context) -> DeletingAwareUITextField {
520→    let textField = DeletingAwareUITextField(frame: .zero)
521→    textField.borderStyle = .none
522→    textField.font = UIFont.systemFont(ofSize: 16)
523→    textField.textColor = .label
524→    textField.backgroundColor = .clear
525→    textField.returnKeyType = returnKeyType
526→    textField.placeholder = placeholder
527→    textField.attributedPlaceholder = NSAttributedString(
528→      string: placeholder,
529→      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
530→    )
531→    textField.delegate = context.coordinator
532→    textField.onEmptyBackspace = onEmptyBackspace
533→    textField.addTarget(
534→      context.coordinator,
535→      action: #selector(Coordinator.handleEditingChanged(_:)),
536→      for: .editingChanged
537→    )
538→    return textField
539→  }
540→
541→  func updateUIView(_ uiView: DeletingAwareUITextField, context: Context) {
542→    if uiView.text != text {
543→      uiView.text = text
544→    }
545→
546→    uiView.returnKeyType = returnKeyType
547→    uiView.placeholder = placeholder
548→    uiView.attributedPlaceholder = NSAttributedString(
549→      string: placeholder,
550→      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
551→    )
552→    uiView.onEmptyBackspace = onEmptyBackspace
553→
554→    // Keep coordinator's closures in sync with the latest values
555→    context.coordinator.update(
556→      text: $text,
557→      isFocused: $isFocused,
558→      blurOnSubmit: blurOnSubmit,
559→      onFocus: onFocus,
560→      onBlur: onBlur,
561→      onSubmit: onSubmit
562→    )
563→
564→    let isFirst = uiView.isFirstResponder
565→    if isFocused && !isFirst && !context.coordinator.didEndEditing {
566→      uiView.becomeFirstResponder()
567→    } else if !isFocused && isFirst {
568→      uiView.resignFirstResponder()
569→    }
570→  }
571→
572→  func makeCoordinator() -> Coordinator {
573→    Coordinator(
574→      text: $text,
575→      isFocused: $isFocused,
576→      blurOnSubmit: blurOnSubmit,
577→      onFocus: onFocus,
578→      onBlur: onBlur,
579→      onSubmit: onSubmit
580→    )
581→  }
582→
583→  final class Coordinator: NSObject, UITextFieldDelegate {
584→    private var text: Binding<String>
585→    private var isFocused: Binding<Bool>
586→    private var blurOnSubmit: Bool
587→    private var onFocus: () -> Void
588→    private var onBlur: () -> Void
589→    private var onSubmit: () -> Void
590→    /// Set when editing ends to prevent updateUIView from re-focusing
591→    /// before SwiftUI processes the isFocused binding change.
592→    var didEndEditing: Bool = false
593→
594→    init(
595→      text: Binding<String>,
596→      isFocused: Binding<Bool>,
597→      blurOnSubmit: Bool,
598→      onFocus: @escaping () -> Void,
599→      onBlur: @escaping () -> Void,
600→      onSubmit: @escaping () -> Void
601→    ) {
602→      self.text = text
603→      self.isFocused = isFocused
604→      self.blurOnSubmit = blurOnSubmit
605→      self.onFocus = onFocus
606→      self.onBlur = onBlur
607→      self.onSubmit = onSubmit
608→    }
609→
610→    func update(
611→      text: Binding<String>,
612→      isFocused: Binding<Bool>,
613→      blurOnSubmit: Bool,
614→      onFocus: @escaping () -> Void,
615→      onBlur: @escaping () -> Void,
616→      onSubmit: @escaping () -> Void
617→    ) {
618→      self.text = text
619→      self.isFocused = isFocused
620→      self.blurOnSubmit = blurOnSubmit
621→      self.onFocus = onFocus
622→      self.onBlur = onBlur
623→      self.onSubmit = onSubmit
624→    }
625→
626→    @objc
627→    func handleEditingChanged(_ textField: UITextField) {
628→      text.wrappedValue = textField.text ?? ""
629→    }
630→
631→    func textFieldDidBeginEditing(_ textField: UITextField) {
632→      didEndEditing = false
633→      if !isFocused.wrappedValue {
634→        isFocused.wrappedValue = true
635→      }
636→      onFocus()
637→    }
638→
639→    func textFieldDidEndEditing(_ textField: UITextField) {
640→      didEndEditing = true
641→      if isFocused.wrappedValue {
642→        isFocused.wrappedValue = false
643→      }
644→      onBlur()
645→    }
646→
647→    func textFieldShouldReturn(_ textField: UITextField) -> Bool {
648→      onSubmit()
649→      if blurOnSubmit {
650→        isFocused.wrappedValue = false
651→        textField.resignFirstResponder()
652→      }
653→      return true
654→    }
655→  }
656→}
